export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => survives(cell, liveCells));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const cell: Cell = [x + dx, y + dy];
        candidates.set(`${cell[0]},${cell[1]}`, cell);
      }
    }
  }
  const births: Cell[] = [];
  for (const cell of candidates.values()) {
    if (liveCells.some(([lx, ly]) => lx === cell[0] && ly === cell[1])) continue;
    if (countLiveNeighbors(cell, liveCells) === 3) births.push(cell);
  }
  return [...survivors, ...births];
}

