  const liveNeighborCount = countLiveNeighbors(cell, liveCells);
  return liveNeighborCount === 2 || liveNeighborCount === 3;
}

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  return liveCells.filter((cell) => survives(cell, liveCells));
